const jwt = require('jsonwebtoken');

// Load secret/key from secure configuration (environment variable, secrets manager, etc.)
// Never hardcode secrets in source code.
function getJwtSecret() {
  const secret = process.env.JWT_SECRET;
  if (!secret) {
    throw new Error('JWT_SECRET environment variable is not set. Cannot verify tokens.');
  }
  // Ensure the secret has sufficient entropy (at least 32 bytes for HS256)
  if (Buffer.byteLength(secret, 'utf8') < 32) {
    throw new Error('JWT_SECRET is too short. Use at least 32 bytes for HMAC-based algorithms.');
  }
  return secret;
}

// For RSA/EC-based verification, load the public key from secure configuration.
function getJwtPublicKey() {
  const publicKey = process.env.JWT_PUBLIC_KEY;
  if (!publicKey) {
    return null; // Fall back to symmetric secret if no public key is configured
  }
  return publicKey;
}

// Determine the algorithm and corresponding key based on configuration
function getVerificationConfig() {
  const publicKey = getJwtPublicKey();

  if (publicKey) {
    // Asymmetric verification (preferred for production)
    return {
      key: publicKey,
      algorithms: ['RS256'], // Explicit algorithm allowlist — only RS256 accepted
    };
  }

  // Symmetric verification (acceptable for prototypes with strong secrets)
  return {
    key: getJwtSecret(),
    algorithms: ['HS256'], // Explicit algorithm allowlist — only HS256 accepted
  };
}

/**
 * JWT verification middleware for Express.
 *
 * Security properties:
 * - Verifies signature with explicit algorithm allowlisting (never trusts token header alone)
 * - Requires expiration claim (rejects tokens without `exp`)
 * - Validates issuer and audience when configured
 * - Uses keys from environment configuration, never hardcoded
 * - Rejects malformed, expired, or tampered tokens
 */
function jwtAuthMiddleware(req, res, next) {
  // Extract token from Authorization header (Bearer scheme)
  const authHeader = req.headers.authorization;

  if (!authHeader) {
    return res.status(401).json({
      error: 'Authentication required',
      message: 'No Authorization header provided.',
    });
  }

  const parts = authHeader.split(' ');

  if (parts.length !== 2 || parts[0].toLowerCase() !== 'bearer') {
    return res.status(401).json({
      error: 'Authentication required',
      message: 'Authorization header must use Bearer scheme: "Bearer <token>".',
    });
  }

  const token = parts[1];

  if (!token || token.trim() === '') {
    return res.status(401).json({
      error: 'Authentication required',
      message: 'Token is empty.',
    });
  }

  let verificationConfig;
  try {
    verificationConfig = getVerificationConfig();
  } catch (configError) {
    console.error('JWT configuration error:', configError.message);
    return res.status(500).json({
      error: 'Server configuration error',
      message: 'Authentication system is misconfigured.',
    });
  }

  // Build verification options with security requirements
  const verifyOptions = {
    // CRITICAL: Explicit algorithm allowlist prevents algorithm confusion attacks.
    // Never omit this — without it, an attacker could forge tokens using "none"
    // or switch from RS256 to HS256 using the public key as an HMAC secret.
    algorithms: verificationConfig.algorithms,

    // Require the `exp` claim and reject expired tokens.
    // This ensures tokens cannot be used indefinitely.
    requireExp: true,

    // Clock tolerance for slight time differences between servers (in seconds)
    clockTolerance: 30,

    // Validate issuer if configured (prevents tokens from untrusted issuers)
    ...(process.env.JWT_ISSUER && { issuer: process.env.JWT_ISSUER }),

    // Validate audience if configured (prevents tokens intended for other services)
    ...(process.env.JWT_AUDIENCE && { audience: process.env.JWT_AUDIENCE }),
  };

  // SECURE: Use jwt.verify() which validates the signature and claims.
  // NEVER use jwt.decode() for authentication — it does NOT verify the signature.
  try {
    const decoded = jwt.verify(token, verificationConfig.key, verifyOptions);

    // Additional validation: ensure essential user claims are present
    if (!decoded.sub && !decoded.userId && !decoded.id) {
      return res.status(401).json({
        error: 'Invalid token',
        message: 'Token is missing a subject or user identifier claim.',
      });
    }

    // Attach verified user information to the request object
    req.user = {
      id: decoded.sub || decoded.userId || decoded.id,
      email: decoded.email || null,
      name: decoded.name || null,
      roles: Array.isArray(decoded.roles) ? decoded.roles : [],
      // Preserve the full set of verified claims for downstream use
      claims: decoded,
    };

    // Attach token metadata for logging/auditing
    req.tokenInfo = {
      issuedAt: decoded.iat ? new Date(decoded.iat * 1000).toISOString() : null,
      expiresAt: decoded.exp ? new Date(decoded.exp * 1000).toISOString() : null,
      issuer: decoded.iss || null,
      audience: decoded.aud || null,
      tokenId: decoded.jti || null,
    };

    next();
  } catch (err) {
    // Handle specific JWT error types with appropriate messages
    if (err instanceof jwt.TokenExpiredError) {
      return res.status(401).json({
        error: 'Token expired',
        message: 'Your authentication token has expired. Please sign in again.',
        expiredAt: err.expiredAt,
      });
    }

    if (err instanceof jwt.JsonWebTokenError) {
      // This covers: invalid signature, malformed token, algorithm mismatch,
      // missing required claims, invalid issuer/audience, etc.
      console.warn('JWT verification failed:', err.message);
      return res.status(401).json({
        error: 'Invalid token',
        message: 'The provided token is invalid or has been tampered with.',
      });
    }

    if (err instanceof jwt.NotBeforeError) {
      return res.status(401).json({
        error: 'Token not yet active',
        message: 'This token is not yet valid.',
        activeAt: err.date,
      });
    }

    // Unexpected errors
    console.error('Unexpected JWT error:', err);
    return res.status(500).json({
      error: 'Authentication error',
      message: 'An unexpected error occurred during authentication.',
    });
  }
}

/**
 * Optional: Role-based authorization middleware.
 * Use after jwtAuthMiddleware to restrict access based on user roles.
 *
 * Usage: app.get('/admin', jwtAuthMiddleware, requireRoles('admin'), handler)
 */
function requireRoles(...requiredRoles) {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({
        error: 'Authentication required',
        message: 'You must be authenticated to access this resource.',
      });
    }

    const userRoles = req.user.roles || [];
    const hasRequiredRole = requiredRoles.some((role) => userRoles.includes(role));

    if (!hasRequiredRole) {
      return res.status(403).json({
        error: 'Insufficient permissions',
        message: `This resource requires one of the following roles: ${requiredRoles.join(', ')}.`,
      });
    }

    next();
  };
}

module.exports = {
  jwtAuthMiddleware,
  requireRoles,
};

